#include<bits/stdc++.h>
using namespace std;
char s[101][101];
int f[55][32768];
int n,k,m,match[51][51];
const int mod=1e6+3;
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(f,0,sizeof(f));
        memset(match,0,sizeof(match));
        scanf("%d%d",&n,&k);
        for(int i=1;i<=n;i++)
        {
            scanf("%s",s[i]+1);
        }
        m=strlen(s[1]+1);
        for(int i=1;i<=m;i++)
        {
            for(char ch='a';ch<='z';ch++)
            {
                for(int j=1;j<=n;j++)
                {
                    if(s[j][i]=='?'||s[j][i]==ch)
                    {
                        match[i][ch-'a']|=(1<<(j-1));
                    }
                }
            }
        }
        f[1][(1<<n)-1]=1;
        for(int i=1;i<=m;i++)
        {
            for(int j=0;j<(1<<n);j++)
            {
                if(f[i][j])
                {
                    for(char ch='a';ch<='z';ch++)
                    {
                        f[i+1][match[i][ch-'a']&j]=(f[i+1][match[i][ch-'a']&j]+f[i][j])%mod;
                    }
                }
            }
        }
        int ans=0;
        for(int i=0;i<(1<<n);i++)
        {
            int tmp=0;
            for(int j=1;j<(1<<n);j*=2)
            {
                tmp+=(bool)(i&j);
            }
            if(tmp==k)
            {
                ans=(ans+f[m+1][i])%mod;
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
